function getPresident(monthsSince){
  for(const p of PRESIDENTS) if(monthsSince>=p.terms[0]&&monthsSince<=p.terms[1]) return p;
  return PRESIDENTS[PRESIDENTS.length-1];
}

function generateNewsletter(){
  const c=GS.char, inv=GS.inv;
  if(!c||!inv) return;

  const monthsSince = Math.max(0, c.monthAge-264);
  const gameYear    = GAME_START_YEAR + Math.floor(monthsSince/12);
  const monthName   = MONTH_NAMES[monthsSince%12];

  // President
  const pres   = getPresident(monthsSince);
  const action = pick(PRESIDENT_ACTIONS[pres.style]||PRESIDENT_ACTIONS.moderate);
  const politics = `President ${pres.name} (${pres.party}) ${action}`;

  // Wars: tick existing, randomly start/end
  if(!GS.activeWars) GS.activeWars=[];
  GS.activeWars.forEach(w=>{ w.monthsActive=(w.monthsActive||0)+1; });
  GS.activeWars=GS.activeWars.filter(w=>w.monthsActive<ri(18,42));
  if(GS.activeWars.length===0&&pct(0.45)){
    GS.activeWars.push({...pick(WAR_POOL),monthsActive:0});
  } else if(GS.activeWars.length>0&&GS.activeWars.length<2&&pct(0.08)){
    const avail=WAR_POOL.filter(w=>!GS.activeWars.find(a=>a.name===w.name));
    if(avail.length) GS.activeWars.push({...pick(avail),monthsActive:0});
  }
  const warsText = GS.activeWars.length
    ? GS.activeWars.map(w=>`${w.icon} <b>${w.name}</b> (${w.parties}): ${w.desc}`).join('<br><br>')
    : 'ðŸ•Šï¸� No major active conflicts this month. Global tensions remain elevated but diplomacy is holding. Markets breathe a cautious sigh of relief.';

  // Gas & Inflation
  const gasText = GAS_INFLATION[inv.climate]||GAS_INFLATION.normal;

  // Laws (1â€“2 per month)
  const shuffledLaws=[...LAW_POOL].sort(()=>Math.random()-0.5);
  const laws=shuffledLaws.slice(0, pct(0.35)?2:1);
  const lawsText=laws.map(l=>`<b>${l.title}:</b> ${l.desc}`).join('<br><br>');

  // Stock summary
  const stockChanges=inv.stocks.map(s=>{
    const h=s.history; const prev=h&&h.length>1?h[h.length-2]:s.price;
    const chg=prev>0?(s.price-prev)/prev*100:0;
    return {name:s.name,id:s.id,price:s.price,chg};
  }).sort((a,b)=>b.chg-a.chg);
  const gainers=stockChanges.slice(0,3);
  const losers=stockChanges.slice(-2).reverse();
  const moodMap={bull:'Bulls dominate â€” momentum traders piling in, valuations stretched.',bear:'Bears in control â€” defensive sectors outperform, cash hoarding rises.',bubble:'Euphoria stage â€” valuation metrics stretched beyond historical norms.',recession:'Recession trade active â€” utilities and bonds sought, growth stocks punished.',normal:'Mixed signals â€” sector rotation ongoing, no clear directional trend.'};
  const stocksText=`<b>Market: ${inv.climate.toUpperCase()}</b> â€” ${moodMap[inv.climate]||'Cautious sentiment.'}<br><br>`
    +`ðŸ“ˆ <b>Top Gainers:</b> ${gainers.map(s=>`${s.name} <span style="color:var(--green)">${s.chg>=0?'+':''}${s.chg.toFixed(1)}%</span>`).join(' Â· ')}<br>`
    +`ðŸ“‰ <b>Decliners:</b> ${losers.map(s=>`${s.name} <span style="color:var(--red)">${s.chg>=0?'+':''}${s.chg.toFixed(1)}%</span>`).join(' Â· ')}`;

  // Crypto summary
  const cryptoChanges=inv.cryptos.map(cx=>{
    const h=cx.history; const prev=h&&h.length>1?h[h.length-2]:cx.price;
    const chg=prev>0?(cx.price-prev)/prev*100:0;
    const fmtP=cx.price>=1000?'$'+(cx.price/1000).toFixed(1)+'k':cx.price>=1?'$'+cx.price.toFixed(0):'$'+cx.price.toFixed(4);
    return {name:cx.name,id:cx.id,price:cx.price,fmtP,chg};
  }).sort((a,b)=>b.chg-a.chg);
  let cryptoText=cryptoChanges.map(cx=>{
    const arrow=cx.chg>0?'â–²':'â–¼';
    const col=cx.chg>0?'var(--green)':'var(--red)';
    const note=cx.chg>25?'parabolic â€” FOMO buying':cx.chg>8?'bullish momentum':cx.chg>0?'modest gain':cx.chg<-25?'severe crash â€” stop losses triggered':cx.chg<-8?'bears pressing':'slight dip';
    return `<b>${cx.name}</b> (${cx.fmtP}) <span style="color:${col}">${arrow}${Math.abs(cx.chg).toFixed(1)}%</span> â€” ${note}`;
  }).join('<br>');
  const bigMove=cryptoChanges.find(cx=>Math.abs(cx.chg)>30);
  if(bigMove) cryptoText+=`<br><br>âš¡ <b>ALERT:</b> ${bigMove.name} ${bigMove.chg>0?'surged':'crashed'} ${Math.abs(bigMove.chg).toFixed(0)}% â€” ${bigMove.chg>0?'whale accumulation detected, retail following':'major holder liquidation, cascading margin calls reported'}`;

  const nl={
    id:`nl_${c.monthAge}`,
    date:`${monthName} ${gameYear}`,
    subject:`${monthName} ${gameYear} Monthly Briefing`,
    read:false,
    politics, wars:warsText, gasInflation:gasText, laws:lawsText, stocks:stocksText, crypto:cryptoText,
  };

  if(!GS.newsletters) GS.newsletters=[];
  GS.newsletters.unshift(nl);
  if(GS.newsletters.length>24) GS.newsletters.pop();
}

function renderInbox(){
  const list=document.getElementById('inbox-list');
  const badge=document.getElementById('inbox-badge');
  if(!list) return;
  const newsletters=GS.newsletters||[];
  const unread=newsletters.filter(n=>!n.read).length;
  if(badge){badge.textContent=unread;badge.className=unread>0?'show':'';}
  if(!newsletters.length){
    list.innerHTML='<div style="color:var(--muted);font-size:11px;text-align:center;padding:20px 10px">Age +1 month to receive your first briefing.</div>';
    return;
  }
  list.innerHTML=newsletters.map(n=>`<div class="inbox-item ${n.read?'read':'unread'}" onclick="openNewsletter('${n.id}')"><div class="ii-date">${n.date}</div><div class="ii-subject">${!n.read?'â—� ':''} ${n.subject}</div><div class="ii-preview">${n.politics.replace(/<[^>]+>/g,'').substring(0,58)}â€¦</div></div>`).join('');
}

function openNewsletter(id){
  const n=(GS.newsletters||[]).find(x=>x.id===id);
  if(!n) return;
  n.read=true;
  renderInbox();
  const overlay=$('modal-overlay');
  $('m-icon').textContent='ðŸ“¬';
  $('m-tag').textContent='Monthly Briefing';
  $('m-tag').className='modal-tag fla';
  $('m-title').textContent=n.subject;
  $('m-result').style.display='none';
  $('m-body').innerHTML=`<div style="text-align:left;max-height:52vh;overflow-y:auto;padding-right:6px">
<div class="nl-section"><div class="nl-stitle pol">ðŸ—³ï¸� White House Update</div><div class="nl-body">${n.politics}</div></div>
<div class="nl-section"><div class="nl-stitle war">âš”ï¸� Global Conflicts</div><div class="nl-body">${n.wars}</div></div>
<div class="nl-section"><div class="nl-stitle eco">â›½ Gas & Inflation</div><div class="nl-body">${n.gasInflation}</div></div>
