function buyStockInline(id){
  const inv=GS.inv,c=GS.char;
  const s=inv.stocks.find(x=>x.id===id);
  const cost=Math.round(s.price*10);
  if(c.checking<cost){showToast('Not enough cash!');return;}
  c.checking-=cost;
  if(!inv.portfolio[id]) inv.portfolio[id]={shares:0,avgCost:0};
  const pos=inv.portfolio[id];
  pos.avgCost=(pos.avgCost*pos.shares+cost)/(pos.shares+10);
  pos.shares+=10;
  showToast(`Bought 10 ${id} Â· ${fmt$(cost)}`);
  _refreshInvModal('stock');
}

function sellStockInline(id){
  const inv=GS.inv,c=GS.char;
  const pos=inv.portfolio[id];
  const s=inv.stocks.find(x=>x.id===id);
  if(!pos){showToast('Nothing to sell');return;}
  const val=Math.round(s.price*pos.shares);
  const cg=Math.round((s.price-pos.avgCost)*pos.shares);
  const tax=cg>0?Math.round(cg*0.15):0;
  c.checking+=val-tax;
  delete inv.portfolio[id];
  showToast(`Sold ${id}: ${fmt$(val-tax)} after tax`);
  _refreshInvModal('stock');
}

function buyCryptoInline(id){
  const inv=GS.inv,c=GS.char;
  const coin=inv.cryptos.find(x=>x.id===id);
  if(c.checking<1000){showToast('Need $1,000 to buy');return;}
  const coins=1000/coin.price;
  c.checking-=1000;
  if(!inv.cryptoHeld[id]) inv.cryptoHeld[id]={coins:0,avgCost:0};
  const pos=inv.cryptoHeld[id];
  pos.avgCost=(pos.avgCost*pos.coins+1000)/(pos.coins+coins);
  pos.coins+=coins;
  showToast(`Bought $1,000 of ${id}`);
  _refreshInvModal('crypto');
}

function sellCryptoInline(id){
  const inv=GS.inv,c=GS.char;
  const pos=inv.cryptoHeld[id];
  const coin=inv.cryptos.find(x=>x.id===id);
  if(!pos){showToast('Nothing to sell');return;}
